class Solution:
    def maxGCDScore(self, nums: List[int], k: int) -> int:
        n = len(nums)
        prefix_gcd = [nums[0]]
        for i in range(1, n):
            prefix_gcd.append(gcd(prefix_gcd[-1], nums[i]))
        dp = [[0, 0] for _ in range(n + 1)]
        for i in range(1, n + 1):
            for j in range(i):
                if k > 0:
                    dp[i][0] = max(dp[i][0], dp[j][0] + (i - j) * prefix_gcd[i - 1])
                else:
                    dp[i][0] = max(dp[i][0], dp[j][0] + (i - j) * prefix_gcd[i - 1] // prefix_gcd[j - 1])
                dp[i][1] = max(dp[i][1], dp[j][1] + (i - j) * prefix_gcd[i - 1])
        return dp[-1][0]
